package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithRecordSeparatorChar() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        char recordSeparator = '\n';

        CSVFormat resultFormat = baseFormat.withRecordSeparator(recordSeparator);

        assertNotNull(resultFormat);
        assertEquals(String.valueOf(recordSeparator), resultFormat.getRecordSeparator());
        // Ensure original instance is not changed (immutability)
        assertNotSame(baseFormat, resultFormat);
    }

    @Test
    void testWithRecordSeparatorCharDifferent() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        char recordSeparator = '\r';

        CSVFormat resultFormat = baseFormat.withRecordSeparator(recordSeparator);

        assertNotNull(resultFormat);
        assertEquals(String.valueOf(recordSeparator), resultFormat.getRecordSeparator());
        assertNotSame(baseFormat, resultFormat);
    }

    @Test
    void testWithRecordSeparatorCharSpecialCharacter() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        char recordSeparator = '\u2028'; // Unicode line separator

        CSVFormat resultFormat = baseFormat.withRecordSeparator(recordSeparator);

        assertNotNull(resultFormat);
        assertEquals(String.valueOf(recordSeparator), resultFormat.getRecordSeparator());
        assertNotSame(baseFormat, resultFormat);
    }
}
